mapper.select:
SELECT m.patient_id AS patientId, m.patient_name AS patientName, CONCAT(COALESCE(m.dept_name, '未知病区'), ' | ', COALESCE(m.bed_no, '--')) AS wardBed, m.current_heart_rate AS heartRate, CASE m.monitor_status WHEN 1 THEN '正常' WHEN 2 THEN '预警' ELSE '正常' END AS status, DATE_FORMAT(m.latest_update_time, '%Y-%m-%d %H:%i:%s') AS updateTime FROM ecg_real_time_monitor m WHERE m.is_deleted = 0 AND m.is_key_monitor = 0 AND m.monitor_status IN (1, 2)
AND m.dept_id = #{req.wardId}
AND m.warning_level = #{req.level}
ORDER BY CASE m.monitor_status WHEN 2 THEN 1 ELSE 2 END, m.latest_update_time DESC, m.monitor_id DESC
